  filter(metric == "relative_likelihood_estimation_error") %>%
  mutate(
    resample_type_cat = case_when(
      resample_type == resample_types[1] ~ resample_type_names[1],
      resample_type == resample_types[2] ~ resample_type_names[2],
      resample_type == resample_types[3] ~ resample_type_names[3],
      resample_type == resample_types[4] ~ resample_type_names[4],
      resample_type == resample_types[5] ~ resample_type_names[5],
      TRUE ~ resample_type
    )
  ) %>%
  mutate(
    resample_type_cat = factor(
      resample_type_cat,
      levels = resample_type_names
    )
  ) %>%
  mutate(use_smoothing_weights = if_else(use_smoothing_weights, "smoothing weights", "standard weights")) %>%
  mutate(
    use_smoothing_weights = factor(
      use_smoothing_weights,
      levels = c("standard weights", "smoothing weights")
    )
  ) %>%
  ggplot(mapping = aes(x = resample_type_cat, y = log(value + 1) + 5473.27)) +
  geom_boxplot() +
  geom_hline(yintercept = 5473.27, linetype = "dashed") +
  theme_classic() +
  facet_wrap(~use_smoothing_weights)



results %>%
mutate(
    resample_type_cat = case_when(
      resample_type == resample_types[1] ~ resample_type_names[1],
      resample_type == resample_types[2] ~ resample_type_names[2],
      resample_type == resample_types[3] ~ resample_type_names[3],
      resample_type == resample_types[4] ~ resample_type_names[4],
      resample_type == resample_types[5] ~ resample_type_names[5],
      TRUE ~ resample_type
    )
  ) %>%
  mutate(
    resample_type_cat = factor(
      resample_type_cat,
      levels = resample_type_names
    )
  ) %>%
  mutate(use_smoothing_weights = if_else(use_smoothing_weights, "smoothing weights", "standard weights")) %>%
  mutate(
    use_smoothing_weights = factor(
      use_smoothing_weights,
      levels = c("standard weights", "smoothing weights")
    )
  ) %>%
  filter(metric == "relative_likelihood_estimation_error") %>%
  mutate(relative_estimate = value + 1) %>%
  mutate(log_estimate = log(relative_estimate) + 5473.27) %>%
  select(resample_type_cat, use_smoothing_weights, log_estimate, relative_estimate) %>%
  pivot_longer(c(log_estimate, relative_estimate), names_to = "type", values_to = "value") %>%
  group_by(resample_type_cat, use_smoothing_weights, type) %>%
  reframe(mean = mean(value), median = median(value), sd = sd(value)) %>%
  arrange(use_smoothing_weights, type) %>%
  rename("Resampling weights" = "use_smoothing_weights") %>%
  rename("Resampling scheme" = "resample_type_cat") -> results_table


n_decimal_places <- 2

results_table %>%
  filter(type == "log_estimate") %>%
  mutate(
    mean = format(round(mean, digits = n_decimal_places), nsmall = n_decimal_places),
    sd = paste0("($\\pm$", format(round(sd, digits = n_decimal_places), nsmall = n_decimal_places), ")")
  ) %>%
  mutate(`Resampling scheme` = as.character(`Resampling scheme`)) %>%
  select(!c(median, type)) %>%
  unite("This work ($\\pm$std\\,dev.)", c(mean, sd), sep = " ")   %>%
  bind_rows(
    tibble(
      `Resampling scheme` = "Ground truth",
      `Resampling weights` = "",
      `This work ($\\pm$std\\,dev.)` = "5473.36"
    )
  ) %>%
  bind_cols(
    tibble(
      `Kviman et al. (2024)` = c("", 5468.77, "", 5473.37, "", "", "", "", 5470.68, "", 5469.39)
    )
  ) %>%
  xtable::xtable(type = "latex") %>%
  print(include.rownames = FALSE, sanitize.text.function = function(x){x})


